class PlayerData {
    private userInfo: any = {};
    private currencies: any = {
        incense_money: 0,      // 香火钱
        yuanbao: 0,            // 元宝
        merit: 0,              // 功德
        incense_sticks: 0,     // 线香
        candles: 0,            // 蜡烛
        gold_paper: 0,         // 金纸
        fruits: 0,             // 供果
        mana: 100,             // 法力
        cultivation: 0         // 修为
    };
    private level: number = 1;
    private stage: string = 'clay'; // clay, wood, bronze, gold
    private token: string = '';
    
    async load() {
        // 从本地存储加载
        const saved = localStorage.getItem('caishen_player');
        if (saved) {
            const data = JSON.parse(saved);
            this.userInfo = data.userInfo || {};
            this.currencies = data.currencies || this.currencies;
            this.level = data.level || 1;
            this.stage = data.stage || 'clay';
        }
    }
    
    save() {
        localStorage.setItem('caishen_player', JSON.stringify({
            userInfo: this.userInfo,
            currencies: this.currencies,
            level: this.level,
            stage: this.stage
        }));
    }
    
    isLoggedIn(): boolean {
        return !!this.token;
    }
    
    setToken(token: string) {
        this.token = token;
        localStorage.setItem('caishen_token', token);
    }
    
    setUserInfo(info: any) {
        this.userInfo = info;
        this.save();
    }
    
    getUserInfo(): any {
        return this.userInfo;
    }
    
    // 货币操作
    getCurrency(type: string): number {
        return this.currencies[type] || 0;
    }
    
    addCurrency(type: string, amount: number) {
        this.currencies[type] = (this.currencies[type] || 0) + amount;
        this.save();
    }
    
    costCurrency(type: string, amount: number): boolean {
        if (this.currencies[type] >= amount) {
            this.currencies[type] -= amount;
            this.save();
            return true;
        }
        return false;
    }
    
    getLevel(): number {
        return this.level;
    }
    
    setLevel(level: number) {
        this.level = level;
        this.save();
    }
    
    getStage(): string {
        return this.stage;
    }
    
    setStage(stage: string) {
        this.stage = stage;
        this.save();
    }
}

export { PlayerData };
